(function(){"use strict";function y(){let n,t;do n=Math.random();while(n===0);return t=Math.random(),Math.sqrt(-2*Math.log(n))*Math.cos(2*Math.PI*t)}function S(n,t){let a=0;for(const s of n){const e=s.type==="CE"?Math.max(t-s.strike,0):Math.max(s.strike-t,0),r=s.action==="buy"?1:-1;a+=r*s.qty*(e-s.premium)}return a}function x(n){const{spot:t,sigma:a,mu:s,nPaths:e,days:r,legs:P}=n,i=r*8,h=r/365/i,A=(s-.5*a*a)*h,E=a*Math.sqrt(h),d=Math.max(1,Math.ceil(i/100)),w=Math.ceil(i/d)+1,m=new Array(e),p=new Array(e);let M=1/0,f=-1/0;for(let l=0;l<e;l++){const u=new Array(w);u[0]=t;let o=t,g=1;for(let c=1;c<=i;c++)o=o*Math.exp(A+E*y()),(c%d===0||c===i)&&(u[g++]=o,o<M&&(M=o),o>f&&(f=o));m[l]=u.slice(0,g),p[l]=S(P,o)}return{paths:m,finalPnls:p,spotMin:M,spotMax:f}}self.onmessage=n=>{const t=x(n.data);self.postMessage(t)}})();
